const express = require('express');

//Create the app
const app = express();

const path = require("path");
app.use(express.static(__dirname));


//Start the server 127.0.0.1:3000
app.listen(3000, () => {
    console.log('listening on port 3000');
  });

 //Route - /?name=
app.get("/", (req, res) => {
    const userName = req.query.name;
    const dateTime = new Date();

    if(userName && userName!=='undefined'){
        var myDateStr = dateTime.toString();
        console.log('["'+ userName +'", "'+myDateStr+'"]');
        //res.write('["'+ userName +'", "'+myDateStr+'"]');
        res.send(JSON.stringify([userName, myDateStr]));
    } else{
      res.end(); 
    }
});